package be.schaubroeck.lpb.rkm.rekenmotor.rsz.werkbonus.basisbedrag;

import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.SleutelGegevens;
import be.schaubroeck.lpb.rkm.rekenmotor.WerkbonusLuik;
import be.schaubroeck.lpb.rkm.rekenmotor.util.ConstantManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.TimeTools;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.RszConstant;
import be.schaubroeck.lpb.tools.enumtypes.Konstanten;
import be.schaubroeck.lpb.tools.rsz.RszConstantType;
import be.schaubroeck.lpb.tools.service.RszConstantService;
import lombok.AllArgsConstructor;
import org.joda.time.LocalDate;

@AllArgsConstructor
public class WerkbonusBasisBedragFactory {

    private static final int PRIVE = 1;

    private static final LocalDate VERANDERING_REDENERING_BASISBEDRAG = new LocalDate(2008, 10, 1);
    private static final LocalDate VERANDERING_REDENERING_BASISBEDRAG_2013 = new LocalDate(2013, 1, 1);
    private static final LocalDate VERANDERING_REDENERING_BASISBEDRAG_2022 = new LocalDate(2022, 1, 1);
    private static final LocalDate VERANDERING_REDENERING_BASISBEDRAG_2023 = new LocalDate(2023, 7, 1);
    private static final LocalDate VERANDERING_REDENERING_BASISBEDRAG_2024 = new LocalDate(2024, 4, 1);

    private final ConstantManager constantManager;
    private final RszConstantService rszConstantService;

    public WerkbonusBasisBedrag create(WerkbonusLuik luik, boolean isRegelingArbeiderPrive, LocalDate selectieDatum) {
        if (luik == WerkbonusLuik.LUIK_A) {
            return createLuikA(isRegelingArbeiderPrive, selectieDatum);
        } else {
            return createLuikB(isRegelingArbeiderPrive, selectieDatum);
        }
    }

    private WerkbonusBasisBedrag createLuikA(boolean isRegelingArbeiderPrive, LocalDate selectieDatum) {
        if (selectieDatum.isBefore(VERANDERING_REDENERING_BASISBEDRAG)) {
            return new WerkbonusBasisBedragVoor2008(constantManager, selectieDatum);
        } else if (selectieDatum.isBefore(VERANDERING_REDENERING_BASISBEDRAG_2013)) {
            return new WerkbonusBasisBedragVanaf2008(constantManager, selectieDatum);
        } else if (selectieDatum.isBefore(VERANDERING_REDENERING_BASISBEDRAG_2022)) {
            return new WerkbonusBasisBedragVanaf2013(constantManager, selectieDatum);
        } else if (selectieDatum.isBefore(VERANDERING_REDENERING_BASISBEDRAG_2023)) {
            return redeneringBasisBedragVanaf2022(isRegelingArbeiderPrive, selectieDatum);
        } else if (selectieDatum.isBefore(VERANDERING_REDENERING_BASISBEDRAG_2024)) {
            return redeneringBasisBedragVanaf2023(isRegelingArbeiderPrive, selectieDatum);
        } else {
            return redeneringBasisBedragVanaf2024LuikA(isRegelingArbeiderPrive, selectieDatum);
        }
    }

    private WerkbonusBasisBedrag createLuikB(boolean isRegelingArbeiderPrive, LocalDate selectieDatum) {
        if (selectieDatum.isBefore(VERANDERING_REDENERING_BASISBEDRAG_2024)) {
            return new WerkbonusBasisBedragAlwaysZero();
        } else {
            return redeneringBasisBedragVanaf2024LuikB(isRegelingArbeiderPrive, selectieDatum);
        }
    }

    public WerkbonusBasisBedrag redeneringBasisBedragVanaf2022(boolean isRegelingArbeiderPrive, LocalDate selectieDatum) {
        if (isRegelingArbeiderPrive) {
            return new WerkbonusBasisBedragVanaf2022ArbeiderPrive(constantManager, selectieDatum);
        } else {
            return new WerkbonusBasisBedragVanaf2013(constantManager, selectieDatum);
        }
    }

    public WerkbonusBasisBedrag redeneringBasisBedragVanaf2023(boolean isRegelingArbeiderPrive, LocalDate selectieDatum) {
        if (isRegelingArbeiderPrive) {
            return new WerkbonusBasisBedragVanaf2023ArbeiderPrive(constantManager, selectieDatum);
        } else {
            return new WerkbonusBasisBedragVanaf2023(constantManager, selectieDatum);
        }
    }

    public WerkbonusBasisBedrag redeneringBasisBedragVanaf2024LuikA(boolean isRegelingArbeiderPrive, LocalDate selectieDatum) {
        if (isRegelingArbeiderPrive) {
            return new WerkbonusBasisBedragVanaf2024ArbeiderPriveLuikA(constantManager, selectieDatum);
        } else {
            return new WerkbonusBasisBedragVanaf2024LuikA(constantManager, selectieDatum);
        }
    }

    public WerkbonusBasisBedrag redeneringBasisBedragVanaf2024LuikB(boolean isRegelingArbeiderPrive, LocalDate selectieDatum) {
        if (isRegelingArbeiderPrive) {
            return new WerkbonusBasisBedragVanaf2024ArbeiderPriveLuikB(constantManager, selectieDatum);
        } else {
            return new WerkbonusBasisBedragVanaf2024LuikB(constantManager, selectieDatum);
        }
    }

    public Money bereken(SleutelGegevens gegevens, Money referentieLoon, RekenTijd rekenTijd, WerkbonusLuik werkbonusLuik) {
        boolean isRegelingArbeiderPrive = isRegelingArbeiderPrive(gegevens, rekenTijd);
        WerkbonusBasisBedrag werkbonusBasisBedrag = create(werkbonusLuik, isRegelingArbeiderPrive, rekenTijd.eindDatum);
        return werkbonusBasisBedrag.bereken(referentieLoon);
    }


    public Money begrensOpForfait(Money bedragVermindering, WerkbonusLuik luik, RekenTijd rekenTijd) {
        WerkbonusBasisBedrag werkbonusBasisBedrag = create(luik, true, rekenTijd.eindDatum);
        return bedragVermindering.min(werkbonusBasisBedrag.getBegrenstForfait());
    }

    private boolean isRegelingArbeiderPrive(SleutelGegevens gegevens, RekenTijd rekenTijd) {
        Integer isPrive = constantManager.getByCodeDatum(Konstanten.CST_PUBLIEK_PRIVE, rekenTijd.eindDatum).getInteger();
        return isPrive == PRIVE && heeftVerhogingBassi(gegevens, rekenTijd);
    }

    private boolean heeftVerhogingBassi(SleutelGegevens gegevens, RekenTijd rekenTijd) {
        LocalDate datum = TimeTools.getZoekDatum(gegevens, rekenTijd.rekenPeriode);
        RszConstant rszConstant = rszConstantService
                .getByWerkgeversCategorieEnWerknemersKengetalEnDatum(gegevens.getWerkgeversCategorie(), gegevens.getWerknemersKengetal(), datum);
        return rszConstant != null && rszConstant.getType() == RszConstantType.TYPE_1.getCode();
    }

}
